    public static IEnumerable<object[]> KeyPairInvalidParameterSizes()
    {
        yield return [MLKEM768.PublicKeySize + 1, MLKEM768.PrivateKeySize];
        yield return [MLKEM768.PublicKeySize - 1, MLKEM768.PrivateKeySize];
        yield return [MLKEM768.PublicKeySize, MLKEM768.PrivateKeySize + 1];
        yield return [MLKEM768.PublicKeySize, MLKEM768.PrivateKeySize - 1];
    }

    [TestMethod]
    public void Constants_Valid()
    {
        Assert.AreEqual((int)Interop.Libsodium.crypto_kem_mlkem768_publickeybytes(), MLKEM768.PublicKeySize);
        Assert.AreEqual((int)Interop.Libsodium.crypto_kem_mlkem768_secretkeybytes(), MLKEM768.PrivateKeySize);
        Assert.AreEqual((int)Interop.Libsodium.crypto_kem_mlkem768_seedbytes(), MLKEM768.SeedSize);
        Assert.AreEqual((int)Interop.Libsodium.crypto_kem_mlkem768_sharedsecretbytes(), MLKEM768.SharedSecretSize);
        Assert.AreEqual((int)Interop.Libsodium.crypto_kem_mlkem768_ciphertextbytes(), MLKEM768.CiphertextSize);
    }

    [TestMethod]
    public void GenerateKeyPair_Valid()
    {
        Span<byte> pk = stackalloc byte[MLKEM768.PublicKeySize];
        Span<byte> sk = stackalloc byte[MLKEM768.PrivateKeySize];

        MLKEM768.GenerateKeyPair(pk, sk);

        Assert.IsFalse(pk.SequenceEqual(new byte[pk.Length]));
        Assert.IsFalse(sk.SequenceEqual(new byte[sk.Length]));
    }

    [TestMethod]
    [DynamicData(nameof(KeyPairInvalidParameterSizes))]
    public void GenerateKeyPair_Invalid(int publicKeySize, int privateKeySize)
    {
        var pk = new byte[publicKeySize];
        var sk = new byte[privateKeySize];

        Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => MLKEM768.GenerateKeyPair(pk, sk));
    }

    [TestMethod]
    [DynamicData(nameof(KeyPairTestVectors))]
    public void GenerateKeyPair_Seed_Valid(string publicKey, string privateKey, string seed)
    {
        Span<byte> pk = stackalloc byte[MLKEM768.PublicKeySize];
        Span<byte> sk = stackalloc byte[MLKEM768.PrivateKeySize];
        Span<byte> s = Convert.FromHexString(seed);

        MLKEM768.GenerateKeyPair(pk, sk, s);

        Assert.AreEqual(publicKey, Convert.ToHexString(pk).ToLower());
        Assert.AreEqual(privateKey, Convert.ToHexString(sk).ToLower());
    }

    [TestMethod]
    [DynamicData(nameof(KeyPairInvalidParameterSizes))]
    [DataRow(MLKEM768.PublicKeySize, MLKEM768.PrivateKeySize, MLKEM768.SeedSize + 1)]
    [DataRow(MLKEM768.PublicKeySize, MLKEM768.PrivateKeySize, MLKEM768.SeedSize - 1)]
    public void GenerateKeyPair_Seed_Invalid(int publicKeySize, int privateKeySize, int seedSize = MLKEM768.SeedSize)
    {
        var pk = new byte[publicKeySize];
        var sk = new byte[privateKeySize];
        var s = new byte[seedSize];

        Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => MLKEM768.GenerateKeyPair(pk, sk, s));
    }

    // Encapsulate is randomised so cannot be tested with test vectors
    [TestMethod]
    [DynamicData(nameof(KeyPairTestVectors))]
    public void Encapsulate_Decapsulate_Valid(string recipientPublicKey, string recipientPrivateKey, string _)
    {
        Span<byte> sss = stackalloc byte[MLKEM768.SharedSecretSize];
        Span<byte> rss = stackalloc byte[MLKEM768.SharedSecretSize];
        Span<byte> c = stackalloc byte[MLKEM768.CiphertextSize];
        Span<byte> rpk = Convert.FromHexString(recipientPublicKey);
        Span<byte> rsk = Convert.FromHexString(recipientPrivateKey);

        MLKEM768.Encapsulate(sss, c, rpk);

        Assert.IsFalse(sss.SequenceEqual(new byte[sss.Length]));
        Assert.IsFalse(c.SequenceEqual(new byte[c.Length]));

        MLKEM768.Decapsulate(rss, c, rsk);

        Assert.IsTrue(sss.SequenceEqual(rss));
    }

    [TestMethod]
    [DynamicData(nameof(TamperedPublicKeyTestVectors))]
    public void Encapsulate_Tampered(string recipientPublicKey)
    {
        var ss = new byte[MLKEM768.SharedSecretSize];
        var c = new byte[MLKEM768.CiphertextSize];
        var rpk = Convert.FromHexString(recipientPublicKey);

        Assert.ThrowsExactly<CryptographicException>(() => MLKEM768.Encapsulate(ss, c, rpk));
    }

    [TestMethod]
    [DataRow(MLKEM768.SharedSecretSize + 1, MLKEM768.CiphertextSize, MLKEM768.PublicKeySize)]
    [DataRow(MLKEM768.SharedSecretSize - 1, MLKEM768.CiphertextSize, MLKEM768.PublicKeySize)]
    [DataRow(MLKEM768.SharedSecretSize, MLKEM768.CiphertextSize + 1, MLKEM768.PublicKeySize)]
    [DataRow(MLKEM768.SharedSecretSize, MLKEM768.CiphertextSize - 1, MLKEM768.PublicKeySize)]
    [DataRow(MLKEM768.SharedSecretSize, MLKEM768.CiphertextSize, MLKEM768.PublicKeySize + 1)]
    [DataRow(MLKEM768.SharedSecretSize, MLKEM768.CiphertextSize, MLKEM768.PublicKeySize - 1)]
    public void Encapsulate_Invalid(int sharedSecretSize, int ciphertextSize, int recipientPublicKeySize)
    {
        var ss = new byte[sharedSecretSize];
        var c = new byte[ciphertextSize];
        var rpk = new byte[recipientPublicKeySize];

        Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => MLKEM768.Encapsulate(ss, c, rpk));
    }

    [TestMethod]
    [DynamicData(nameof(DecapsulateTestVectors))]
    public void Decapsulate_Valid(string sharedSecret, string ciphertext, string recipientPrivateKey)
    {
        Span<byte> ss = stackalloc byte[MLKEM768.SharedSecretSize];
        Span<byte> c = Convert.FromHexString(ciphertext);
        Span<byte> rsk = Convert.FromHexString(recipientPrivateKey);

        MLKEM768.Decapsulate(ss, c, rsk);

        Assert.AreEqual(sharedSecret, Convert.ToHexString(ss).ToLower());
    }

    [TestMethod]
    [DataRow(MLKEM768.SharedSecretSize + 1, MLKEM768.CiphertextSize, MLKEM768.PrivateKeySize)]
    [DataRow(MLKEM768.SharedSecretSize - 1, MLKEM768.CiphertextSize, MLKEM768.PrivateKeySize)]
    [DataRow(MLKEM768.SharedSecretSize, MLKEM768.CiphertextSize + 1, MLKEM768.PrivateKeySize)]
    [DataRow(MLKEM768.SharedSecretSize, MLKEM768.CiphertextSize - 1, MLKEM768.PrivateKeySize)]
    [DataRow(MLKEM768.SharedSecretSize, MLKEM768.CiphertextSize, MLKEM768.PrivateKeySize + 1)]
    [DataRow(MLKEM768.SharedSecretSize, MLKEM768.CiphertextSize, MLKEM768.PrivateKeySize - 1)]
    public void Decapsulate_Invalid(int sharedSecretSize, int ciphertextSize, int recipientPrivateKeySize)
    {
        var ss = new byte[sharedSecretSize];
        var c = new byte[ciphertextSize];
        var rsk = new byte[recipientPrivateKeySize];

        Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => MLKEM768.Decapsulate(ss, c, rsk));
    }
